function debounce(fn, delay) {
  let timer;
  function debounced(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  }
  debounced.cancel = () => clearTimeout(timer);
  return debounced;
}

let runs = 0;
const search = debounce((q) => {
  runs++;
  console.log("API call for:", q, "(total calls:", runs + ")");
}, 50);

// Simulate fast typing — only the LAST one should fire
search("r"); search("re"); search("rea"); search("react");
console.log("4 keystrokes fired, calls so far:", runs); // 0 — still waiting

var g = "global";

function demo() {
  var f = "function-scoped";
  if (true) {
    let b = "block-only";          // confined to this block
    var leaks = "var ignores blocks";
    console.log("inside block:", f, b);
  }
  console.log("var leaked out:", leaks);   // var is function-scoped → visible
  try {
    console.log(b);                         // let did NOT leak
  } catch (e) {
    console.log("b outside block:", e.name); // "ReferenceError"
  }
}

demo();
console.log("global still visible:", g);

const user = {
  name: "Ada",
  greet() { return "Hi, " + (this ? this.name : "?"); },
};

console.log(user.greet());            // "Hi, Ada"  (method call → this = user)

const loose = user.greet;
console.log(loose());                  // "Hi, undefined" (receiver lost)

const bound = user.greet.bind(user);
console.log(bound());                  // "Hi, Ada"  (explicit binding)

