// class syntax — but it's prototypes underneath
class Animal { speak() { return "…"; } }
class Dog extends Animal { speak() { return "woof"; } }
const d = new Dog();
console.log(d.speak());                    // "woof"
console.log(typeof Dog);                   // "function" — not a real class!
console.log(Object.getPrototypeOf(d) === Dog.prototype);              // true
console.log(Object.getPrototypeOf(Dog.prototype) === Animal.prototype); // true

// The same object-to-object link without any class keyword
const proto = { area() { return this.w * this.h; } };
const rect = Object.create(proto);   // rect inherits directly from proto
rect.w = 3; rect.h = 4;
console.log(rect.area());                  // 12

function Animal(name) { this.name = name; }
Animal.prototype.speak = function () {
  return this.name + " makes a sound";
};

function Dog(name) { Animal.call(this, name); }   // inherit instance fields
Dog.prototype = Object.create(Animal.prototype);  // link the chain
Dog.prototype.constructor = Dog;
Dog.prototype.speak = function () {               // override
  return this.name + " barks";
};

const rex = new Dog("Rex");
console.log(rex.speak());                       // "Rex barks"
console.log(rex.name);                          // "Rex" (own property)
console.log(rex instanceof Animal);             // true
console.log(Object.getPrototypeOf(rex) === Dog.prototype); // true
console.log(rex.hasOwnProperty("speak"));       // false — lives on the prototype

