// Make a plain object iterable
function range(start, end) {
  return {
    [Symbol.iterator]() {
      let i = start;
      return {
        next: () =>
          i <= end ? { value: i++, done: false } : { value: undefined, done: true },
      };
    },
  };
}

console.log([...range(1, 4)]);        // [1, 2, 3, 4]  (spread consumes it)
for (const n of range(5, 7)) console.log("n =", n); // 5, 6, 7

// Built-ins are iterable too
console.log([..."hi"]);               // ["h", "i"]

// A classic callback API: cb(err, data)
function loadUser(id, cb) {
  setTimeout(() => {
    if (id <= 0) cb(new Error("bad id"));
    else cb(null, { id, name: "User" + id });
  }, 30);
}

// Promisified wrapper
function loadUserP(id) {
  return new Promise((resolve, reject) => {
    loadUser(id, (err, data) => (err ? reject(err) : resolve(data)));
  });
}

console.log("kicked off async load…");
loadUserP(7)
  .then((u) => console.log("resolved:", u))
  .catch((e) => console.log("rejected:", e.message));

const original = { user: { name: "Ada" }, tags: ["a"], when: new Date(0) };

// shallow: nested object is SHARED
const shallow = { ...original };
shallow.user.name = "Grace";
console.log(original.user.name);  // "Grace" — leaked! (shared ref)

// deep with structuredClone — fully independent, keeps Dates
const deep = structuredClone(original);
deep.user.name = "Lin";
console.log(original.user.name, deep.user.name); // "Grace" "Lin"
console.log(deep.when instanceof Date);           // true

// JSON method is lossy: Date becomes a string
console.log(typeof JSON.parse(JSON.stringify(original)).when); // "string"

function fetchPrice(item) {
  return new Promise((resolve) =>
    setTimeout(() => resolve(item === "book" ? 12 : 5), 20),
  );
}

// (2) Promise chaining
fetchPrice("book").then((p) => console.log("then →", p));

// (3) async/await + parallel with Promise.all
(async () => {
  const [book, pen] = await Promise.all([fetchPrice("book"), fetchPrice("pen")]);
  console.log("await + Promise.all →", book, pen, "total", book + pen);
})();

function throttle(fn, interval) {
  let last = 0;
  return function (...args) {
    const now = Date.now();
    if (now - last >= interval) {
      last = now;
      return fn.apply(this, args);
    }
  };
}

let painted = 0;
const onScroll = throttle(() => {
  painted++;
  console.log("paint #" + painted);
}, 100);

// Fire a rapid burst synchronously — only the first gets through the window
onScroll(); onScroll(); onScroll(); onScroll();
console.log("4 scroll events, actual paints:", painted); // 1

// Modern AJAX with fetch + async/await
async function loadUser(id) {
  const res = await fetch("/api/users/" + id);
  if (!res.ok) throw new Error("HTTP " + res.status);
  return res.json();
}

// The legacy equivalent with XMLHttpRequest
