xhr.open("GET", "/api/users/1");
xhr.responseType = "json";
xhr.onload = () => { if (xhr.status === 200) console.log(xhr.response); };
xhr.onerror = () => console.error("network error");
xhr.send();

function parse(json) {
  try { return JSON.parse(json); }
  catch (err) { return { error: err.name }; }
  finally { console.log("attempted"); }       // always runs
}
console.log(parse('{"ok":true}'));   // attempted → { ok: true }
console.log(parse("oops"));           // attempted → { error: "SyntaxError" }

// async/await: a rejected promise IS catchable with try...catch
(async () => {
  try { await Promise.reject(new Error("boom")); }
  catch (e) { console.log("caught async:", e.message); } // "boom"
})();

class Animal {}
class Dog extends Animal {}
const d = new Dog();

console.log(d instanceof Dog);     // true
console.log(d instanceof Animal);  // true (further up the chain)
console.log(d instanceof Object);  // true (everything inherits Object)
console.log(d instanceof Array);   // false

// primitives are NOT instances of their wrapper
console.log("hi" instanceof String);   // false
console.log(typeof "hi");                // "string" — use typeof for primitives

// arrays: prefer Array.isArray (realm-safe)
console.log([] instanceof Array, Array.isArray([])); // true true

// GET with proper error handling (fetch won't reject on 404/500!)
async function getUser(id) {
  const res = await fetch("/api/users/" + id);
  if (!res.ok) throw new Error("HTTP " + res.status); // must check ok
  return res.json();                                    // body parse is async
}

// POST JSON
async function createUser(data) {
  const res = await fetch("/api/users", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  return res.json();
}

