const meta = new WeakMap();
let node = { id: "header" };

meta.set(node, { clicks: 0 });        // attach private metadata
console.log(meta.get(node));           // { clicks: 0 }
console.log(meta.has(node));           // true

// keys MUST be objects
try { meta.set("str", 1); } catch (e) { console.log(e.name); } // "TypeError"

// not iterable, no size (consequence of weak refs)
console.log("size" in meta, typeof meta[Symbol.iterator]); // false "undefined"

// once 'node' is unreachable elsewhere, the entry becomes GC-eligible
node = null;

// var is hoisted and initialized to undefined
console.log(typeof v);   // "undefined" (no error)
var v = 1;

// let/const live in the Temporal Dead Zone until declared
try {
  console.log(notYet);   // touched before declaration
  let notYet = 1;
} catch (e) {
  console.log(e.name);   // "ReferenceError"  (TDZ)
}

// const locks the binding, not the contents
const obj = { n: 1 };
obj.n = 2;               // allowed — mutating contents
console.log(obj.n);      // 2

async function* counter(max) {
  for (let i = 1; i <= max; i++) {
    // each value can come from awaited async work
    yield await Promise.resolve(i);
  }
}

console.log("loop starts asynchronously after this line");

(async () => {
  const collected = [];
  for await (const n of counter(4)) collected.push(n);
  console.log("collected:", collected); // [1, 2, 3, 4]
})();
